318	    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
319	        GameState gs_after_tilt = current_gs_after_placement;
320	        gs_after_tilt.apply_tilt(i);
321	
322	        double eval = eval_lookahead(gs_after_tilt, turn_T, config.max_depth, config);
323	
324	        if (eval > best_overall_eval) {
325	            best_overall_eval = eval;
326	            best_dir_idx = i;
327	        }
328	    }
329	    return DIR_CHARS[best_dir_idx];
330	}
