    void place_candy_at_idx(int idx, int flavor) {
        board[idx] = static_cast<uint8_t>(flavor);
        num_candies++;
    }

    int find_pth_empty_cell_idx(int p_1_indexed) const {
        int count = 0;
        for (int i = 0; i < BOARD_SIZE; ++i) {
            if (board[i] == 0) {
                count++;
                if (count == p_1_indexed) {
                    return i;
                }
            }
        }
