    void apply_tilt(int dir_idx) {
        if (dir_idx == 0) { // Forward (toward row 0)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = 0;
                for (int r = 0; r < GRID_SIZE; ++r) {
                    uint8_t v = board[r * GRID_SIZE + c];
                    if (v != 0) {
                        if (r != write_r) {
                            board[write_r * GRID_SIZE + c] = v;
                            board[r * GRID_SIZE + c] = 0;
                        }
                        write_r++;
                    }
                }
            }
        } else if (dir_idx == 1) { // Backward (toward row 9)
            for (int c = 0; c < GRID_SIZE; ++c) {
                int write_r = GRID_SIZE - 1;
                for (int r = GRID_SIZE - 1; r >= 0; --r) {
                    uint8_t v = board[r * GRID_SIZE + c];
                    if (v != 0) {
                        if (r != write_r) {
                            board[write_r * GRID_SIZE + c] = v;
                            board[r * GRID_SIZE + c] = 0;
                        }
                        write_r--;
                    }
                }
            }
        } else if (dir_idx == 2) { // Left (toward col 0)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int base = r * GRID_SIZE;
                int write_c = 0;
                for (int c = 0; c < GRID_SIZE; ++c) {
                    uint8_t v = board[base + c];
                    if (v != 0) {
                        if (c != write_c) {
                            board[base + write_c] = v;
                            board[base + c] = 0;
                        }
                        write_c++;
                    }
                }
            }
        } else { // Right (toward col 9)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int base = r * GRID_SIZE;
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    uint8_t v = board[base + c];
                    if (v != 0) {
                        if (c != write_c) {
                            board[base + write_c] = v;
                            board[base + c] = 0;
                        }
                        write_c--;
                    }
                }
            }
        }
    }

    double evaluate_fast(int turn) const {
        if (num_candies == 0) return 0.0;

        int same_adj = 0;
        int diff_adj = 0;
        double sum_r[NUM_FLAVORS + 1] = {};
        double sum_c[NUM_FLAVORS + 1] = {};
        int counts[NUM_FLAVORS + 1] = {};

        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t f = board[base + c];
                if (f == 0) continue;
                counts[f]++;
                sum_r[f] += r;
                sum_c[f] += c;
                if (c + 1 < GRID_SIZE) {
                    uint8_t right = board[base + c + 1];
                    if (right == f) same_adj++;
                    else if (right != 0) diff_adj++;
                }
                if (r + 1 < GRID_SIZE) {
                    uint8_t below = board[base + GRID_SIZE + c];
                    if (below == f) same_adj++;
                    else if (below != 0) diff_adj++;
