                    }
                }
            }
        } else { // Right (toward col 9)
            for (int r = 0; r < GRID_SIZE; ++r) {
                int base = r * GRID_SIZE;
                int write_c = GRID_SIZE - 1;
                for (int c = GRID_SIZE - 1; c >= 0; --c) {
                    uint8_t v = board[base + c];
                    if (v != 0) {
                        if (c != write_c) {
                            board[base + write_c] = v;
                            board[base + c] = 0;
                        }
                        write_c--;
                    }
                }
            }
        }
    }

    double evaluate_fast(int turn) const {
        if (num_candies == 0) return 0.0;

        int same_adj = 0;
        int diff_adj = 0;
        double sum_r[NUM_FLAVORS + 1] = {};
        double sum_c[NUM_FLAVORS + 1] = {};
        int counts[NUM_FLAVORS + 1] = {};

        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t f = board[base + c];
                if (f == 0) continue;
                counts[f]++;
                sum_r[f] += r;
                sum_c[f] += c;
                if (c + 1 < GRID_SIZE) {
                    uint8_t right = board[base + c + 1];
                    if (right == f) same_adj++;
                    else if (right != 0) diff_adj++;
                }
                if (r + 1 < GRID_SIZE) {
                    uint8_t below = board[base + GRID_SIZE + c];
                    if (below == f) same_adj++;
                    else if (below != 0) diff_adj++;
                }
            }
        }

        double compactness = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t f = board[base + c];
                if (f != 0 && counts[f] > 1) {
                    double com_r = sum_r[f] / counts[f];
                    double com_c = sum_c[f] / counts[f];
                    compactness += std::abs(r - com_r) + std::abs(c - com_c);
                }
            }
        }

        double t = static_cast<double>(turn);
        return (80.0 + 3.0 * t) * same_adj
             - (10.0 + 0.5 * t) * diff_adj
             - std::max(0.0, 180.0 - 1.8 * t) * compactness;
    }

    double evaluate(int turn) const {
        if (num_candies == 0) return 0.0;

        long long total_sq_sum = 0;
        bool visited[BOARD_SIZE] = {};
        int queue[BOARD_SIZE];

        for (int i = 0; i < BOARD_SIZE; ++i) {
            if (board[i] != 0 && !visited[i]) {
                uint8_t flavor = board[i];
                int comp_size = 0;
                queue[0] = i;
                visited[i] = true;
                int head = 0, tail = 1;

                while (head < tail) {
                    comp_size++;
                    int pos = queue[head++];
                    int r = pos / GRID_SIZE;
                    int c = pos % GRID_SIZE;
                    if (r > 0 && !visited[pos - GRID_SIZE] && board[pos - GRID_SIZE] == flavor) {
                        visited[pos - GRID_SIZE] = true;
                        queue[tail++] = pos - GRID_SIZE;
                    }
                    if (r < GRID_SIZE - 1 && !visited[pos + GRID_SIZE] && board[pos + GRID_SIZE] == flavor) {
                        visited[pos + GRID_SIZE] = true;
                        queue[tail++] = pos + GRID_SIZE;
                    }
                    if (c > 0 && !visited[pos - 1] && board[pos - 1] == flavor) {
                        visited[pos - 1] = true;
                        queue[tail++] = pos - 1;
                    }
                    if (c < GRID_SIZE - 1 && !visited[pos + 1] && board[pos + 1] == flavor) {
                        visited[pos + 1] = true;
                        queue[tail++] = pos + 1;
                    }
                }
                total_sq_sum += (long long)comp_size * comp_size;
            }
        }

        int same_adj = 0;
        int diff_adj = 0;
        double sum_r[NUM_FLAVORS + 1] = {};
        double sum_c[NUM_FLAVORS + 1] = {};
        int counts[NUM_FLAVORS + 1] = {};

        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t f = board[base + c];
                if (f == 0) continue;
                counts[f]++;
                sum_r[f] += r;
                sum_c[f] += c;
                if (c + 1 < GRID_SIZE) {
                    uint8_t right = board[base + c + 1];
                    if (right == f) same_adj++;
                    else if (right != 0) diff_adj++;
                }
                if (r + 1 < GRID_SIZE) {
                    uint8_t below = board[base + GRID_SIZE + c];
                    if (below == f) same_adj++;
                    else if (below != 0) diff_adj++;
                }
            }
        }

        double compactness = 0.0;
        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t f = board[base + c];
                if (f != 0 && counts[f] > 1) {
                    double com_r = sum_r[f] / counts[f];
                    double com_c = sum_c[f] / counts[f];
                    compactness += std::abs(r - com_r) + std::abs(c - com_c);
                }
            }
        }

        double separation = 0.0;
        double com_r[NUM_FLAVORS + 1] = {};
        double com_c[NUM_FLAVORS + 1] = {};
        for (int f = 1; f <= NUM_FLAVORS; ++f) {
            if (counts[f] > 0) {
                com_r[f] = sum_r[f] / counts[f];
                com_c[f] = sum_c[f] / counts[f];
            }
        }
        for (int f1 = 1; f1 <= NUM_FLAVORS; ++f1) {
            if (counts[f1] == 0) continue;
            for (int f2 = f1 + 1; f2 <= NUM_FLAVORS; ++f2) {
                if (counts[f2] == 0) continue;
                separation += std::abs(com_r[f1] - com_r[f2]) + std::abs(com_c[f1] - com_c[f2]);
            }
        }

        double t = static_cast<double>(turn);

        double conn_weight = 15.0 + 1.5 * t;
        double adj_weight = 80.0 + 3.0 * t;
        double diff_adj_weight = -(10.0 + 0.5 * t);
        double compactness_weight = -std::max(0.0, 180.0 - 1.8 * t);
        double separation_weight = std::max(0.0, 40.0 - 0.3 * t);

        return conn_weight * total_sq_sum
             + adj_weight * same_adj
             + diff_adj_weight * diff_adj
             + compactness_weight * compactness
             + separation_weight * separation;
    }
};

struct LookaheadConfig {
    int max_depth;
    int samples[3];
    bool use_fast_at_leaf;
};

double eval_lookahead(GameState& state, int turn, int depth_remaining, const LookaheadConfig& config) {
    if (depth_remaining == 0 || turn >= NUM_TURNS) {
        if (config.use_fast_at_leaf) return state.evaluate_fast(turn);
        return state.evaluate(turn);
    }

    int num_empty = state.count_empty_cells();
    if (num_empty == 0) {
        if (config.use_fast_at_leaf) return state.evaluate_fast(turn);
        return state.evaluate(turn);
    }

    int next_candy_flavor = G_FLAVOR_SEQUENCE[turn];
    int sample_count_param_idx = config.max_depth - depth_remaining;
    int sample_count_this_depth = config.samples[sample_count_param_idx];
    int actual_num_samples = std::min(sample_count_this_depth, num_empty);

    if (actual_num_samples == 0) {
        if (config.use_fast_at_leaf) return state.evaluate_fast(turn);
        return state.evaluate(turn);
    }

    uint8_t saved_board[BOARD_SIZE];
    double sum_over_sampled_placements = 0.0;

    for (int s = 0; s < actual_num_samples; ++s) {
        int p_val;
        if (actual_num_samples == num_empty) {
            p_val = s + 1;
        } else {
            p_val = rng.uniform_int(1, num_empty);
        }

        int cell_idx = state.find_pth_empty_cell_idx(p_val);
        state.board[cell_idx] = static_cast<uint8_t>(next_candy_flavor);
        state.num_candies++;
        int next_turn = turn + 1;

        memcpy(saved_board, state.board, BOARD_SIZE);

        double max_eval = -1e18;
        for (int dir_idx = 0; dir_idx < NUM_DIRECTIONS; ++dir_idx) {
            state.apply_tilt(dir_idx);
            double val = eval_lookahead(state, next_turn, depth_remaining - 1, config);
            if (val > max_eval) max_eval = val;
            memcpy(state.board, saved_board, BOARD_SIZE);
        }
        sum_over_sampled_placements += max_eval;

        // Undo placement
        state.board[cell_idx] = 0;
        state.num_candies--;
    }

    return sum_over_sampled_placements / actual_num_samples;
}


char decide_tilt_direction_logic(GameState& current_gs, int turn, double time_budget_ms) {
    double best_overall_eval = -1e18;
    int best_dir_idx = 0;

    LookaheadConfig config;
    if (turn <= 12) {
        config.max_depth = 3;
        config.samples[0] = 12;
        config.samples[1] = 6;
        config.samples[2] = 3;
        config.use_fast_at_leaf = true;
    } else {
        config.max_depth = 2;
        config.samples[0] = 28;
        config.samples[1] = 7;
        config.samples[2] = 0;
        config.use_fast_at_leaf = false;
    }

    uint8_t saved_board[BOARD_SIZE];
    memcpy(saved_board, current_gs.board, BOARD_SIZE);

    for (int i = 0; i < NUM_DIRECTIONS; ++i) {
        current_gs.apply_tilt(i);
        double eval = eval_lookahead(current_gs, turn, config.max_depth, config);
        if (eval > best_overall_eval) {
            best_overall_eval = eval;
            best_dir_idx = i;
        }
        memcpy(current_gs.board, saved_board, BOARD_SIZE);
    }
    return DIR_CHARS[best_dir_idx];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    G_start_time = std::chrono::steady_clock::now();

    G_flavor_total_counts.fill(0);
    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
        G_flavor_total_counts[G_FLAVOR_SEQUENCE[t]]++;
    }

    GameState current_gs;
    for (int t = 0; t < NUM_TURNS; ++t) {
        int turn = t + 1;

        int p_val;
        std::cin >> p_val;

        int cell_idx = current_gs.find_pth_empty_cell_idx(p_val);
        current_gs.place_candy_at_idx(cell_idx, G_FLAVOR_SEQUENCE[t]);

        double remaining_time = 1900.0 - elapsed_ms();
        double time_per_turn = remaining_time / (NUM_TURNS - t);

        char chosen_dir = decide_tilt_direction_logic(current_gs, turn, time_per_turn);

        std::cout << chosen_dir << std::endl;

        int dir_idx = 0;
        for (int k = 0; k < NUM_DIRECTIONS; ++k) {
            if (DIR_CHARS[k] == chosen_dir) {
                dir_idx = k;
                break;
            }
        }
        current_gs.apply_tilt(dir_idx);
    }

    return 0;
}
