            int write_c = 0;
            for (int c = 0; c < GRID_SIZE; ++c) {
                uint8_t v = board[base + c];
                if (v != 0) {
                    if (c != write_c) {
                        board[base + write_c] = v;
                        board[base + c] = 0;
                    }
                    write_c++;
                }
            }
        }
    } else { // Right (toward col 9)
        for (int r = 0; r < GRID_SIZE; ++r) {
            int base = r * GRID_SIZE;
            int write_c = GRID_SIZE - 1;
            for (int c = GRID_SIZE - 1; c >= 0; --c) {
                uint8_t v = board[base + c];
                if (v != 0) {
                    if (c != write_c) {
                        board[base + write_c] = v;
                        board[base + c] = 0;
                    }
                    write_c--;
                }
            }
        }
    }
}

// Tilt src into dst buffer (no modification of src)
inline void apply_tilt_to(const uint8_t* src, uint8_t* dst, int dir_idx) {
    memcpy(dst, src, BOARD_SIZE);
    apply_tilt_inplace(dst, dir_idx);
}

inline double evaluate_fast(const uint8_t* board, int num_candies, int turn) {
    if (num_candies == 0) return 0.0;

    int same_adj = 0;
    int diff_adj = 0;
    double sum_r[4] = {};
    double sum_c[4] = {};
    int counts[4] = {};

    for (int r = 0; r < GRID_SIZE; ++r) {
        int base = r * GRID_SIZE;
        for (int c = 0; c < GRID_SIZE; ++c) {
            uint8_t f = board[base + c];
            if (f == 0) continue;
            counts[f]++;
            sum_r[f] += r;
            sum_c[f] += c;
            if (c + 1 < GRID_SIZE) {
                uint8_t right = board[base + c + 1];
                if (right == f) same_adj++;
                else if (right != 0) diff_adj++;
            }
            if (r + 1 < GRID_SIZE) {
                uint8_t below = board[base + GRID_SIZE + c];
                if (below == f) same_adj++;
                else if (below != 0) diff_adj++;
            }
        }
    }

    double compactness = 0.0;
    for (int r = 0; r < GRID_SIZE; ++r) {
        int base = r * GRID_SIZE;
        for (int c = 0; c < GRID_SIZE; ++c) {
            uint8_t f = board[base + c];
            if (f != 0 && counts[f] > 1) {
                double com_r = sum_r[f] / counts[f];
                double com_c = sum_c[f] / counts[f];
                compactness += std::abs(r - com_r) + std::abs(c - com_c);
            }
        }
    }

    double t = static_cast<double>(turn);
    return (80.0 + 3.0 * t) * same_adj
         - (10.0 + 0.5 * t) * diff_adj
         - std::max(0.0, 180.0 - 1.8 * t) * compactness;
}

inline double evaluate_full(const uint8_t* board, int num_candies, int turn) {
    if (num_candies == 0) return 0.0;

    long long total_sq_sum = 0;
    bool visited[BOARD_SIZE] = {};
    int queue[BOARD_SIZE];

    for (int i = 0; i < BOARD_SIZE; ++i) {
        if (board[i] != 0 && !visited[i]) {
            uint8_t flavor = board[i];
            int comp_size = 0;
            queue[0] = i;
            visited[i] = true;
            int head = 0, tail = 1;

            while (head < tail) {
                comp_size++;
                int pos = queue[head++];
                int r = pos / GRID_SIZE;
                int c = pos % GRID_SIZE;
                if (r > 0 && !visited[pos - GRID_SIZE] && board[pos - GRID_SIZE] == flavor) {
                    visited[pos - GRID_SIZE] = true;
                    queue[tail++] = pos - GRID_SIZE;
                }
                if (r < GRID_SIZE - 1 && !visited[pos + GRID_SIZE] && board[pos + GRID_SIZE] == flavor) {
                    visited[pos + GRID_SIZE] = true;
                    queue[tail++] = pos + GRID_SIZE;
                }
                if (c > 0 && !visited[pos - 1] && board[pos - 1] == flavor) {
                    visited[pos - 1] = true;
                    queue[tail++] = pos - 1;
                }
                if (c < GRID_SIZE - 1 && !visited[pos + 1] && board[pos + 1] == flavor) {
                    visited[pos + 1] = true;
                    queue[tail++] = pos + 1;
                }
            }
            total_sq_sum += (long long)comp_size * comp_size;
        }
    }

    int same_adj = 0;
    int diff_adj = 0;
    double sum_r[4] = {};
    double sum_c[4] = {};
    int counts[4] = {};

    for (int r = 0; r < GRID_SIZE; ++r) {
        int base = r * GRID_SIZE;
        for (int c = 0; c < GRID_SIZE; ++c) {
            uint8_t f = board[base + c];
            if (f == 0) continue;
            counts[f]++;
            sum_r[f] += r;
            sum_c[f] += c;
            if (c + 1 < GRID_SIZE) {
                uint8_t right = board[base + c + 1];
                if (right == f) same_adj++;
                else if (right != 0) diff_adj++;
            }
            if (r + 1 < GRID_SIZE) {
                uint8_t below = board[base + GRID_SIZE + c];
                if (below == f) same_adj++;
                else if (below != 0) diff_adj++;
            }
        }
    }

    double compactness = 0.0;
    for (int r = 0; r < GRID_SIZE; ++r) {
        int base = r * GRID_SIZE;
        for (int c = 0; c < GRID_SIZE; ++c) {
            uint8_t f = board[base + c];
            if (f != 0 && counts[f] > 1) {
                double com_r = sum_r[f] / counts[f];
                double com_c = sum_c[f] / counts[f];
                compactness += std::abs(r - com_r) + std::abs(c - com_c);
            }
        }
    }

    double separation = 0.0;
    double com_r[4] = {};
    double com_c[4] = {};
    for (int f = 1; f <= NUM_FLAVORS; ++f) {
        if (counts[f] > 0) {
            com_r[f] = sum_r[f] / counts[f];
            com_c[f] = sum_c[f] / counts[f];
        }
    }
    for (int f1 = 1; f1 <= NUM_FLAVORS; ++f1) {
        if (counts[f1] == 0) continue;
        for (int f2 = f1 + 1; f2 <= NUM_FLAVORS; ++f2) {
            if (counts[f2] == 0) continue;
            separation += std::abs(com_r[f1] - com_r[f2]) + std::abs(com_c[f1] - com_c[f2]);
        }
    }

    double t = static_cast<double>(turn);
    double conn_weight = 15.0 + 1.5 * t;
    double adj_weight = 80.0 + 3.0 * t;
    double diff_adj_weight = -(10.0 + 0.5 * t);
    double compactness_weight = -std::max(0.0, 180.0 - 1.8 * t);
    double separation_weight = std::max(0.0, 40.0 - 0.3 * t);

    return conn_weight * total_sq_sum
         + adj_weight * same_adj
         + diff_adj_weight * diff_adj
         + compactness_weight * compactness
         + separation_weight * separation;
}

int find_pth_empty(const uint8_t* board, int p) {
    int count = 0;
    for (int i = 0; i < BOARD_SIZE; ++i) {
        if (board[i] == 0) {
            count++;
            if (count == p) return i;
        }
    }
    return -1;
}

struct LookaheadConfig {
    int max_depth;
    int samples[3];
    bool use_fast_at_leaf;
};

// Recursive lookahead operating on a stack of board buffers to avoid allocation
// We pre-allocate board buffers on the stack at each level.
// Maximum recursion: 3 levels. At each level we need buffers for 4 tilted directions.

// Level buffers: indexed [depth][dir]
uint8_t g_tilt_buf[4][4][BOARD_SIZE]; // [depth_level][dir][cell]

double eval_lookahead_d0(const uint8_t* board, int num_candies, int turn, bool use_fast) {
    if (use_fast) return evaluate_fast(board, num_candies, turn);
    return evaluate_full(board, num_candies, turn);
}

double eval_lookahead_d1(const uint8_t* board_after_tilt, int num_candies, int turn, const LookaheadConfig& config, int depth_level) {
    // depth_remaining = 1: sample placements, for each try 4 tilts, evaluate leaf
    int num_empty = BOARD_SIZE - num_candies;
    if (num_empty == 0 || turn >= NUM_TURNS) {
        return eval_lookahead_d0(board_after_tilt, num_candies, turn, config.use_fast_at_leaf);
    }

    int next_flavor = G_FLAVOR_SEQUENCE[turn];
    int sample_idx = config.max_depth - 1;
    int num_samples = std::min(config.samples[sample_idx], num_empty);
    if (num_samples == 0) return eval_lookahead_d0(board_after_tilt, num_candies, turn, config.use_fast_at_leaf);

    // Work buffer for placement
    uint8_t work[BOARD_SIZE];
    double sum = 0.0;

    for (int s = 0; s < num_samples; ++s) {
        int p_val = (num_samples == num_empty) ? s + 1 : rng.uniform_int(1, num_empty);
        int cell_idx = find_pth_empty(board_after_tilt, p_val);

        // Place candy in work buffer
        memcpy(work, board_after_tilt, BOARD_SIZE);
        work[cell_idx] = static_cast<uint8_t>(next_flavor);
        int new_candies = num_candies + 1;
        int next_turn = turn + 1;

        double max_eval = -1e18;
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            apply_tilt_to(work, g_tilt_buf[depth_level][d], d);
            double val = eval_lookahead_d0(g_tilt_buf[depth_level][d], new_candies, next_turn, config.use_fast_at_leaf);
            if (val > max_eval) max_eval = val;
        }
        sum += max_eval;
    }
    return sum / num_samples;
}

double eval_lookahead_d2(const uint8_t* board_after_tilt, int num_candies, int turn, const LookaheadConfig& config, int depth_level) {
    // depth_remaining = 2: sample placements, for each try 4 tilts, recurse to d1
    int num_empty = BOARD_SIZE - num_candies;
    if (num_empty == 0 || turn >= NUM_TURNS) {
        return evaluate_full(board_after_tilt, num_candies, turn);
    }

    int next_flavor = G_FLAVOR_SEQUENCE[turn];
    int sample_idx = config.max_depth - 2;
    int num_samples = std::min(config.samples[sample_idx], num_empty);
    if (num_samples == 0) return evaluate_full(board_after_tilt, num_candies, turn);

    uint8_t work[BOARD_SIZE];
    double sum = 0.0;

    for (int s = 0; s < num_samples; ++s) {
        int p_val = (num_samples == num_empty) ? s + 1 : rng.uniform_int(1, num_empty);
        int cell_idx = find_pth_empty(board_after_tilt, p_val);

        memcpy(work, board_after_tilt, BOARD_SIZE);
        work[cell_idx] = static_cast<uint8_t>(next_flavor);
        int new_candies = num_candies + 1;
        int next_turn = turn + 1;

        double max_eval = -1e18;
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            apply_tilt_to(work, g_tilt_buf[depth_level][d], d);
            double val = eval_lookahead_d1(g_tilt_buf[depth_level][d], new_candies, next_turn, config, depth_level + 1);
            if (val > max_eval) max_eval = val;
        }
        sum += max_eval;
    }
    return sum / num_samples;
}

double eval_lookahead_d3(const uint8_t* board_after_tilt, int num_candies, int turn, const LookaheadConfig& config, int depth_level) {
    // depth_remaining = 3: sample placements, for each try 4 tilts, recurse to d2
    int num_empty = BOARD_SIZE - num_candies;
    if (num_empty == 0 || turn >= NUM_TURNS) {
        return evaluate_full(board_after_tilt, num_candies, turn);
    }

    int next_flavor = G_FLAVOR_SEQUENCE[turn];
    int sample_idx = config.max_depth - 3;
    int num_samples = std::min(config.samples[sample_idx], num_empty);
    if (num_samples == 0) return evaluate_full(board_after_tilt, num_candies, turn);

    uint8_t work[BOARD_SIZE];
    double sum = 0.0;

    for (int s = 0; s < num_samples; ++s) {
        int p_val = (num_samples == num_empty) ? s + 1 : rng.uniform_int(1, num_empty);
        int cell_idx = find_pth_empty(board_after_tilt, p_val);

        memcpy(work, board_after_tilt, BOARD_SIZE);
        work[cell_idx] = static_cast<uint8_t>(next_flavor);
        int new_candies = num_candies + 1;
        int next_turn = turn + 1;

        double max_eval = -1e18;
        for (int d = 0; d < NUM_DIRECTIONS; ++d) {
            apply_tilt_to(work, g_tilt_buf[depth_level][d], d);
            double val = eval_lookahead_d2(g_tilt_buf[depth_level][d], new_candies, next_turn, config, depth_level + 1);
            if (val > max_eval) max_eval = val;
        }
        sum += max_eval;
    }
    return sum / num_samples;
}

char decide_tilt_direction(const uint8_t* board, int num_candies, int turn) {
    double best_eval = -1e18;
    int best_dir = 0;

    LookaheadConfig config;
    if (turn <= 12) {
        config.max_depth = 3;
        config.samples[0] = 10;
        config.samples[1] = 5;
        config.samples[2] = 3;
        config.use_fast_at_leaf = true;
    } else {
        config.max_depth = 2;
        config.samples[0] = 26;
        config.samples[1] = 6;
        config.samples[2] = 0;
        config.use_fast_at_leaf = false;
    }

    uint8_t tilted[BOARD_SIZE];
    for (int d = 0; d < NUM_DIRECTIONS; ++d) {
        apply_tilt_to(board, tilted, d);
        double val;
        if (config.max_depth == 3) {
            val = eval_lookahead_d3(tilted, num_candies, turn, config, 0);
        } else {
            val = eval_lookahead_d2(tilted, num_candies, turn, config, 0);
        }
        if (val > best_eval) {
            best_eval = val;
            best_dir = d;
        }
    }
    return DIR_CHARS[best_dir];
}


int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    G_start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    for (int t = 0; t < NUM_TURNS; ++t) {
        std::cin >> G_FLAVOR_SEQUENCE[t];
    }

    uint8_t board[BOARD_SIZE];
    memset(board, 0, BOARD_SIZE);
    int num_candies = 0;

    for (int t = 0; t < NUM_TURNS; ++t) {
        int turn = t + 1;

        int p_val;
        std::cin >> p_val;

        int cell_idx = find_pth_empty(board, p_val);
        board[cell_idx] = static_cast<uint8_t>(G_FLAVOR_SEQUENCE[t]);
        num_candies++;

        char chosen_dir = decide_tilt_direction(board, num_candies, turn);

        std::cout << chosen_dir << std::endl;

        int dir_idx = 0;
        for (int k = 0; k < NUM_DIRECTIONS; ++k) {
            if (DIR_CHARS[k] == chosen_dir) {
                dir_idx = k;
                break;
            }
        }
        apply_tilt_inplace(board, dir_idx);
    }

    return 0;
}
