XorshiftRNG rng;

inline void apply_tilt_inplace(uint8_t* board, int dir_idx) {
    if (dir_idx == 0) {
        for (int c = 0; c < 10; ++c) {
            int wr = 0;
            for (int r = 0; r < 10; ++r) {
                uint8_t v = board[r*10+c];
                if (v) { if (r != wr) { board[wr*10+c] = v; board[r*10+c] = 0; } wr++; }
            }
        }
    } else if (dir_idx == 1) {
        for (int c = 0; c < 10; ++c) {
            int wr = 9;
            for (int r = 9; r >= 0; --r) {
                uint8_t v = board[r*10+c];
                if (v) { if (r != wr) { board[wr*10+c] = v; board[r*10+c] = 0; } wr--; }
            }
        }
    } else if (dir_idx == 2) {
        for (int r = 0; r < 10; ++r) {
            int base = r*10, wc = 0;
            for (int c = 0; c < 10; ++c) {
                uint8_t v = board[base+c];
                if (v) { if (c != wc) { board[base+wc] = v; board[base+c] = 0; } wc++; }
            }
        }
    } else {
        for (int r = 0; r < 10; ++r) {
            int base = r*10, wc = 9;
            for (int c = 9; c >= 0; --c) {
                uint8_t v = board[base+c];
                if (v) { if (c != wc) { board[base+wc] = v; board[base+c] = 0; } wc--; }
            }
        }
    }
}

inline double evaluate_fast(const uint8_t* board, int num_candies, int turn) {
    if (num_candies == 0) return 0.0;
    int same_adj = 0, diff_adj = 0;
    double sum_r[4] = {}, sum_c[4] = {};
    int counts[4] = {};

    for (int r = 0; r < 10; ++r) {
        int base = r * 10;
        for (int c = 0; c < 10; ++c) {
            uint8_t f = board[base+c];
            if (!f) continue;
            counts[f]++; sum_r[f] += r; sum_c[f] += c;
            if (c < 9) { uint8_t rt = board[base+c+1]; if (rt==f) same_adj++; else if (rt) diff_adj++; }
            if (r < 9) { uint8_t bl = board[base+10+c]; if (bl==f) same_adj++; else if (bl) diff_adj++; }
        }
    }
    double compactness = 0.0;
    for (int r = 0; r < 10; ++r) {
        int base = r * 10;
        for (int c = 0; c < 10; ++c) {
            uint8_t f = board[base+c];
            if (f && counts[f] > 1) {
                compactness += std::abs(r - sum_r[f]/counts[f]) + std::abs(c - sum_c[f]/counts[f]);
            }
        }
    }
    double t = (double)turn;
    return (80.0+3.0*t)*same_adj - (10.0+0.5*t)*diff_adj - std::max(0.0, 180.0-1.8*t)*compactness;
}

inline double evaluate_full(const uint8_t* board, int num_candies, int turn) {
    if (num_candies == 0) return 0.0;
    long long total_sq = 0;
    bool visited[100] = {};
    int queue[100];
    for (int i = 0; i < 100; ++i) {
        if (board[i] && !visited[i]) {
            uint8_t fl = board[i]; int sz = 0, head = 0, tail = 0;
            queue[tail++] = i; visited[i] = true;
            while (head < tail) {
                sz++; int pos = queue[head++]; int r = pos/10, c = pos%10;
                if (r>0 && !visited[pos-10] && board[pos-10]==fl) { visited[pos-10]=true; queue[tail++]=pos-10; }
                if (r<9 && !visited[pos+10] && board[pos+10]==fl) { visited[pos+10]=true; queue[tail++]=pos+10; }
                if (c>0 && !visited[pos-1] && board[pos-1]==fl) { visited[pos-1]=true; queue[tail++]=pos-1; }
                if (c<9 && !visited[pos+1] && board[pos+1]==fl) { visited[pos+1]=true; queue[tail++]=pos+1; }
            }
            total_sq += (long long)sz*sz;
        }
    }
    int same_adj = 0, diff_adj = 0;
    double sum_r[4]={}, sum_c[4]={};
    int counts[4]={};
    for (int r = 0; r < 10; ++r) {
        int base = r*10;
        for (int c = 0; c < 10; ++c) {
            uint8_t f = board[base+c]; if (!f) continue;
            counts[f]++; sum_r[f] += r; sum_c[f] += c;
            if (c<9) { uint8_t rt=board[base+c+1]; if(rt==f)same_adj++; else if(rt)diff_adj++; }
            if (r<9) { uint8_t bl=board[base+10+c]; if(bl==f)same_adj++; else if(bl)diff_adj++; }
        }
    }
    double compactness = 0.0;
    for (int r = 0; r < 10; ++r) {
        int base = r*10;
        for (int c = 0; c < 10; ++c) {
            uint8_t f = board[base+c];
            if (f && counts[f]>1) compactness += std::abs(r-sum_r[f]/counts[f]) + std::abs(c-sum_c[f]/counts[f]);
        }
    }
    double separation = 0.0;
    double com_r[4]={}, com_c[4]={};
    for (int f=1;f<=3;f++) if(counts[f]) { com_r[f]=sum_r[f]/counts[f]; com_c[f]=sum_c[f]/counts[f]; }
    for (int f1=1;f1<=3;f1++) { if(!counts[f1])continue; for(int f2=f1+1;f2<=3;f2++) { if(!counts[f2])continue; separation+=std::abs(com_r[f1]-com_r[f2])+std::abs(com_c[f1]-com_c[f2]); } }
    double t=(double)turn;
    return (15.0+1.5*t)*total_sq + (80.0+3.0*t)*same_adj - (10.0+0.5*t)*diff_adj - std::max(0.0,180.0-1.8*t)*compactness + std::max(0.0,40.0-0.3*t)*separation;
}

int find_pth_empty(const uint8_t* board, int p) {
    int count = 0;
    for (int i = 0; i < 100; ++i) if (board[i]==0) { count++; if (count==p) return i; }
    return -1;
}

// Unrolled depth functions operating on board buffers

double lookahead_d1(const uint8_t* board, int nc, int turn, int samples, bool fast) {
    int ne = 100 - nc;
    if (ne == 0 || turn >= 100) return fast ? evaluate_fast(board,nc,turn) : evaluate_full(board,nc,turn);
    int nf = G_FLAVOR_SEQUENCE[turn];
    int ns = std::min(samples, ne);
    if (ns == 0) return fast ? evaluate_fast(board,nc,turn) : evaluate_full(board,nc,turn);

    uint8_t work[100], tilted[100];
    double sum = 0.0;
    for (int s = 0; s < ns; ++s) {
        int p = (ns==ne) ? s+1 : rng.uniform_int(1,ne);
        int ci = find_pth_empty(board, p);
        memcpy(work, board, 100);
        work[ci] = (uint8_t)nf;
        double mx = -1e18;
        for (int d = 0; d < 4; ++d) {
            memcpy(tilted, work, 100);
            apply_tilt_inplace(tilted, d);
            double v = fast ? evaluate_fast(tilted,nc+1,turn+1) : evaluate_full(tilted,nc+1,turn+1);
            if (v > mx) mx = v;
        }
        sum += mx;
    }
    return sum / ns;
}

double lookahead_d2(const uint8_t* board, int nc, int turn, int s0, int s1, bool fast) {
    int ne = 100 - nc;
    if (ne == 0 || turn >= 100) return evaluate_full(board,nc,turn);
    int nf = G_FLAVOR_SEQUENCE[turn];
    int ns = std::min(s0, ne);
    if (ns == 0) return evaluate_full(board,nc,turn);

    uint8_t work[100], tilted[100];
    double sum = 0.0;
    for (int s = 0; s < ns; ++s) {
        int p = (ns==ne) ? s+1 : rng.uniform_int(1,ne);
        int ci = find_pth_empty(board, p);
        memcpy(work, board, 100);
        work[ci] = (uint8_t)nf;
        double mx = -1e18;
        for (int d = 0; d < 4; ++d) {
            memcpy(tilted, work, 100);
            apply_tilt_inplace(tilted, d);
            double v = lookahead_d1(tilted, nc+1, turn+1, s1, fast);
            if (v > mx) mx = v;
        }
        sum += mx;
    }
    return sum / ns;
}

double lookahead_d3(const uint8_t* board, int nc, int turn, int s0, int s1, int s2, bool fast) {
    int ne = 100 - nc;
    if (ne == 0 || turn >= 100) return evaluate_full(board,nc,turn);
    int nf = G_FLAVOR_SEQUENCE[turn];
    int ns = std::min(s0, ne);
    if (ns == 0) return evaluate_full(board,nc,turn);

    uint8_t work[100], tilted[100];
    double sum = 0.0;
    for (int s = 0; s < ns; ++s) {
        int p = (ns==ne) ? s+1 : rng.uniform_int(1,ne);
        int ci = find_pth_empty(board, p);
        memcpy(work, board, 100);
        work[ci] = (uint8_t)nf;
        double mx = -1e18;
        for (int d = 0; d < 4; ++d) {
            memcpy(tilted, work, 100);
            apply_tilt_inplace(tilted, d);
            double v = lookahead_d2(tilted, nc+1, turn+1, s1, s2, fast);
            if (v > mx) mx = v;
        }
        sum += mx;
    }
    return sum / ns;
}

char decide_tilt(const uint8_t* board, int nc, int turn) {
    double best = -1e18;
    int best_d = 0;
    uint8_t tilted[100];

    if (turn <= 15) {
        // Extended depth-3 range (was 12, now 15) since we're faster
        for (int d = 0; d < 4; ++d) {
            memcpy(tilted, board, 100);
            apply_tilt_inplace(tilted, d);
            double v = lookahead_d3(tilted, nc, turn, 10, 5, 3, true);
            if (v > best) { best = v; best_d = d; }
        }
    } else {
        for (int d = 0; d < 4; ++d) {
            memcpy(tilted, board, 100);
            apply_tilt_inplace(tilted, d);
            double v = lookahead_d2(tilted, nc, turn, 24, 6, false);
            if (v > best) { best = v; best_d = d; }
        }
    }
    return DIR_CHARS[best_d];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    G_start_time = std::chrono::steady_clock::now();
    rng.seed(std::chrono::steady_clock::now().time_since_epoch().count());

    for (int t = 0; t < 100; ++t) std::cin >> G_FLAVOR_SEQUENCE[t];

    uint8_t board[100];
    memset(board, 0, 100);
    int nc = 0;

    for (int t = 0; t < 100; ++t) {
        int turn = t + 1;
        int p; std::cin >> p;
        int ci = find_pth_empty(board, p);
        board[ci] = (uint8_t)G_FLAVOR_SEQUENCE[t];
        nc++;

        char chosen = decide_tilt(board, nc, turn);
        std::cout << chosen << std::endl;

        int di = 0;
        for (int k = 0; k < 4; ++k) if (DIR_CHARS[k]==chosen) { di=k; break; }
        apply_tilt_inplace(board, di);
    }
    return 0;
}
# EVOLVE-BLOCK-END

