# EVOLVE-BLOCK-START
#include <iostream>
#include <array>
#include <algorithm>
#include <cmath>
#include <limits>
#include <chrono>
#include <cstring>

const int N = 10;
const int B = 100;
const int T = 100;
const char DIR_CHARS[] = {'F', 'B', 'L', 'R'};

int G_SEQ[T];
auto G_start = std::chrono::steady_clock::now();

inline double elapsed_ms() {
    return std::chrono::duration<double, std::milli>(std::chrono::steady_clock::now() - G_start).count();
}

struct RNG {
    uint64_t x;
    RNG(uint64_t s = 1) : x(s ? s : 1) {}
    uint64_t next() { x ^= x << 13; x ^= x >> 7; x ^= x << 17; return x; }
    int randint(int lo, int hi) { return lo + (int)(next() % (uint64_t)(hi - lo + 1)); }
};
