double eval_fast(const uint8_t* b, int nc, int turn) {
    if (nc == 0) return 0.0;
    int sa=0,da=0; double sr[4]={},sc[4]={}; int cnt[4]={};
    for (int r=0;r<N;r++) { int base=r*N; for(int c=0;c<N;c++) { uint8_t f=b[base+c]; if(!f)continue; cnt[f]++;sr[f]+=r;sc[f]+=c; if(c<9){uint8_t x=b[base+c+1];if(x==f)sa++;else if(x)da++;} if(r<9){uint8_t x=b[base+N+c];if(x==f)sa++;else if(x)da++;} } }
