char decide(const uint8_t* board, int nc, int turn) {
    double best=-1e18; int bestd=0;
    uint8_t tb[B];

    // Run evaluation twice and average for reduced variance
    double scores[4] = {};
    int n_runs = 0;
    double deadline_ms = elapsed_ms() + 19.0 * (T - turn + 1); // approximate per-turn budget
    if (deadline_ms > 1880.0) deadline_ms = 1880.0;

    // First run
    if (turn <= 12) {
        for(int dd=0;dd<4;dd++){memcpy(tb,board,B);tilt(tb,dd);scores[dd]=d3(tb,nc,turn,10,5,3,true);}
    } else {
        for(int dd=0;dd<4;dd++){memcpy(tb,board,B);tilt(tb,dd);scores[dd]=d2(tb,nc,turn,24,6,false);}
    }
    n_runs = 1;

    // Second run if time allows
    double now = elapsed_ms();
    if (now < deadline_ms - 5.0) {
        double scores2[4];
        if (turn <= 12) {
            for(int dd=0;dd<4;dd++){memcpy(tb,board,B);tilt(tb,dd);scores2[dd]=d3(tb,nc,turn,10,5,3,true);}
