    int ne = B - nc;
    if (ne==0 || turn>=TURNS) return eval_full(board, nc, turn);
    int nf = G_SEQ[turn], ns = std::min(s0, ne);
    if (ns==0) return eval_full(board, nc, turn);
    uint8_t w[B], t2[B];
    double sum = 0;
    for (int s=0; s<ns; s++) {
        int p = (ns==ne) ? s+1 : rng.randint(1, ne);
        int ci = find_empty(board, p);
        memcpy(w, board, B); w[ci] = (uint8_t)nf;
        double mx = -1e18;
        for (int d=0; d<4; d++) {
            memcpy(t2, w, B); tilt(t2, d);
            double v = look1(t2, nc+1, turn+1, s1, fast);
            if (v > mx) mx = v;
        }
        sum += mx;
    }
    return sum / ns;
}

