char decide(const uint8_t* board, int nc, int turn) {
    double best = -1e18;
    int bestd = 0;
    uint8_t tb[B];

    if (turn <= 12) {
        for (int d=0; d<4; d++) {
            memcpy(tb, board, B); tilt(tb, d);
            double v = look3(tb, nc, turn, 10, 5, 3, true);
            if (v > best) { best = v; bestd = d; }
        }
    } else {
        for (int d=0; d<4; d++) {
            memcpy(tb, board, B); tilt(tb, d);
            double v = look2(tb, nc, turn, 28, 7, false);
            if (v > best) { best = v; bestd = d; }
        }
    }
    return DIR_CHARS[bestd];
}

